const webhookData = $("Webhook – Lead Intake (Estimate)").first().json.body;
const configData = $("Config – GHL IDs").first().json;

const contact = webhookData.contact || {};
const fields = webhookData.fields || {};

// Scoped-write allow-list — estimate tool must NEVER write roof-type fields.
const FIELD_IDS = {
  lead_source: 'pOqyjdxOHg67C4JWdkaG',
  property_address: 'acFCeylcy8uhep3stymL',
  estimated_roof_size: 'S3E1cQMFQ2vD2Ec1nSAR',
  estimate_range: 'cEjn1x0nid6taqIaQxKt',
};

const isEmpty = (v) => v === null || v === undefined || v === '';

const contactFields = {};
for (const key of ['firstName', 'lastName', 'email', 'phone', 'address1']) {
  if (!isEmpty(contact[key])) contactFields[key] = contact[key];
}

const customFields = [];
for (const [key, id] of Object.entries(FIELD_IDS)) {
  if (!isEmpty(fields[key])) customFields.push({ id, value: fields[key] });
}
if (customFields.length) contactFields.customFields = customFields;
const baseTags = Array.isArray(webhookData.tags) && webhookData.tags.length ? webhookData.tags : ['Estimate Tool'];
const allTags = webhookData.smsConsent === true ? [...baseTags, 'SMS Consent'] : baseTags;
contactFields.tags = allTags;

// Add selected_roof_type on create only — never overwrite existing visualizer selection
const createOnlyCustomFields = [];
if (!isEmpty(fields.selected_roof_type)) {
  createOnlyCustomFields.push({ id: 'ooxcklKOKGrDCRunZnh3', value: fields.selected_roof_type });
}
const contactPayloadCreate = { ...contactFields, locationId: configData.locationId,
  ...(createOnlyCustomFields.length ? { customFields: [...(contactFields.customFields || []), ...createOnlyCustomFields] } : {}) };
const contactPayloadUpdate = { ...contactFields };

return [{
  json: {
    email: contact.email,
    contactPayloadCreate,
    contactPayloadUpdate,
    rawFields: fields,
    locationId: configData.locationId,
    pipelineId: configData.pipelineId,
    stageId: configData.stageId,
    firstName: contact.firstName || '',
    lastName: contact.lastName || '',
    phone: contact.phone || '',
    source: webhookData.source || 'estimate',
  },
}];

const search = $("Search Opportunities For Contact").first().json;
const cfg = $("Config – GHL IDs").first().json;
const built = $("Build Contact Payload (Estimate Scoped, Filter Nulls)").first().json;
const normalized = $("Normalize Contact Result").first().json;

const opportunities = Array.isArray(search.opportunities) ? search.opportunities : [];
const existing = opportunities[0] || null;

let opportunityAction = 'create';
let opportunityId = null;

if (existing && existing.id) {
  opportunityId = existing.id;
  opportunityAction = (existing.pipelineStageId === cfg.stageId) ? 'updateStage' : 'noop';
}

return [{
  json: {
    contactId: normalized.contactId,
    firstName: built.firstName,
    lastName: built.lastName,
    phone: built.phone,
    source: built.source,
    locationId: built.locationId,
    pipelineId: built.pipelineId,
    stageId: built.stageId,
    opportunityAction,
    opportunityId,
  },
}];

const webhookData = $("Webhook – Lead Intake (Estimate)").first().json.body;
const configData = $("Config – GHL IDs").first().json;
const contact = webhookData.contact || {};
const fields = webhookData.fields || {};
const utm = webhookData.utm || {};

const FIELD_IDS = {
  property_address: 'acFCeylcy8uhep3stymL',
  estimated_roof_size: 'S3E1cQMFQ2vD2Ec1nSAR',
  estimate_range: 'cEjn1x0nid6taqIaQxKt',
};
const UTM_FIELD_IDS = {
  source: 'NNZiielScQomx8VDF7q8',
  medium: 'ELW45zGCkwQkpUV2TnEW',
  campaign: 'VrI3HZtaymdTdf0lggfD',
};

const isEmpty = (v) => v === null || v === undefined || v === '';

const contactFields = {};
for (const key of ['firstName', 'address1', 'city', 'state', 'postalCode']) {
  if (!isEmpty(contact[key])) contactFields[key] = contact[key];
}

const customFields = [];
for (const [key, id] of Object.entries(FIELD_IDS)) {
  if (!isEmpty(fields[key])) customFields.push({ id, value: fields[key] });
}
for (const [key, id] of Object.entries(UTM_FIELD_IDS)) {
  if (!isEmpty(utm[key])) customFields.push({ id, value: utm[key] });
}
if (customFields.length) contactFields.customFields = customFields;

const contactPayload = { ...contactFields, locationId: configData.locationId, tags: ['Estimate Partial'] };

return [{ json: { contactPayload, locationId: configData.locationId } }];

